text = ""
freq_arr = [0]*26
freq_eng = [0.0812 ,0.0149 ,0.0271 ,0.0432 ,0.1202 ,0.0230 ,0.0203 ,0.0592 ,0.0731 ,0.0010 ,0.0069 ,0.0398 ,0.0261 ,0.0695 ,0.0768 ,0.0182 ,0.0011 ,0.0602 ,0.0628 ,0.0910 ,0.0288 ,0.0111 ,0.0209 ,0.0017 ,0.0211 ,0.0007]

tot = 0
for i in text:
    freq_arr[ord(i)-ord('A')] = freq_arr[ord(i)-ord('A')]+1
    tot = tot + 1

for i in range(0,26):
    freq_arr[i] = freq_arr[i]/tot

guesses = []
for k in range(0,26):
    prob = 0
    for i in range(0,26):
        prob += freq_eng[i]*freq_arr[(i+k)%26]
    
    string = ""
    for i in text:
        string += chr(ord('A') + ((ord(i) - ord('A') - k)%26))
    
    guesses.append([prob, k, string])

best = sorted(guesses, reverse=True)
for i in range(0,3):
    print(f"Top {i+1} Guess: KEY = {best[i][1]} \nDECRYPTED TEXT: {best[i][2]}\n")

